var doc = uiapp.ActiveUIDocument.Document;
if (!doc.IsWorkshared) return new { workshared = false, worksets = new List<object>() };
var wsets = new FilteredWorksetCollector(doc).OfKind(WorksetKind.UserWorkset).Select(w => new { id = w.Id.IntegerValue, name = w.Name, owner = w.Owner, is_open = w.IsOpen }).ToList();
return new { workshared = true, count = wsets.Count, worksets = wsets };
